window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["l"]={"Łukasz": "<b>Łukasz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Loukas</i>, co z kolei jest zhellenizowaną formą <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego imienia</a> <i>Lucius</i>, a w związku z tym tak jak <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, pochodzi od łacińskiego <i>lucius</i>, czyli <i>urodzony o świcie</i>. Inne znaczenie to <i>nosiciel światła</i>, ze względu na pochodzenie imienia od łacińskiego <i>lux</i> które oznacza światło.", "Leszek": "W dokumentach występowało ono w formach <i>Lestek</i> i <i>Lestko</i> – prawdopodobnie jako zdrobnienie niepoświadczonych pełnych imion <i>Lścimir</i> i <i>Lścisław,</i> wywodzących się od słowa <i>lście</i>, oznaczającego „chytrość”.", "Leon": "<b>Leon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. W starożytnej <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Grecji</a> funkcjonowało jako zdrobnienie imion dwuczłonowych, zaczynających się lub kończących (jak <a href=\"https://pl.wikipedia.org/wiki/Pantaleon\" target=\"_blank\" rel=\"noopener noreferrer\">Pantaleon</a>) członem <i>λεων (leon)</i>, który pochodzi albo od słowa oznaczającego po grecku „lud”, albo „lew”. Również od czasów starożytnych uważano to imię za oznaczające „lew”. Imię to pojawiło się także u <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymian</a>, bądź jako zapożyczenie z Grecji, bądź niezależnie.", "Lech": "<b>Lech</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, uformowane od imienia <a href=\"https://pl.wikipedia.org/wiki/Lestek\" target=\"_blank\" rel=\"noopener noreferrer\">Lestek</a>/<a href=\"https://pl.wikipedia.org/wiki/Leszek\" target=\"_blank\" rel=\"noopener noreferrer\">Leszek</a>.", "Ludwik": "<b>Ludwik</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze słowa oznaczającego „głośny”, „sławny”. Jest wersją rozwojową frankońskiego imienia Chlodwig. W pierwszym członie zawarty jest element hlut- (chlod-, chlud-) 'sławny', a w drugim -wik (-wig) 'walka, bitwa'.", "Lucjan": "<b>Lucjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Imię to jest polską wersją łacińskiego <i>Lucianus</i>, co oznacza „należący do <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusza</a>, wywodzący się od Lucjusza”. Jego oboczną formą jest <a href=\"https://pl.wikipedia.org/wiki/%C5%81ucjan\" target=\"_blank\" rel=\"noopener noreferrer\">Łucjan</a>. Patronem imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Lucjan_i_Marcjan_(m%C4%99czennicy)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Lucjan, męczennik z Nikomedii</a> (zm. ok. 250). <i>Bibliotheca Sanctorum</i> zawiera informacje o trzynastu świętych o tym imieniu.", "Leonard": "<b>Leonard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „silny jak lew”. W Polsce imię to poświadczone jest od <a href=\"https://pl.wikipedia.org/wiki/1193\" target=\"_blank\" rel=\"noopener noreferrer\">1193</a> roku, m.in. jako <i>Lenart</i>, <i>Lenard</i>, <i>Leonhardus</i>, <i>Lenert</i>, <i>Lenhart</i> i <i>Lenhard</i>.", "Lesław": "<b>Lesław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia słowiańskiego.", "Leopold": "<b>Leopold</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, wywodzące się od słów <i>leut-</i> 'lud, naród, plemię' i -<i>bald</i> 'odważny' (w formie południowoniemieckiej -<i>pold</i>).", "Leonid": "<b>Leonid</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa λέων oznaczającego „lew”.", "Longin": "<b>Longin</b>, <b>Longinus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrazu <i>Longus</i> oznaczającego „długi”. Żyło 9 świętych katolickich o tym imieniu. Patronem imienia jest męczennik z I wieku św. <a href=\"https://pl.wikipedia.org/wiki/Longin_z_Cezarei_Kapadockiej\" target=\"_blank\" rel=\"noopener noreferrer\">Longin z Cezarei Kapadockiej</a>.", "Łucjan": "<b>Łucjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Imię to jest polską wersją łacińskiego <i>Lucianus</i>, co oznacza „należący do <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusza</a>, wywodzący się od Lucjusza” (w dawnym języku polskim imiona pochodzenia łacińskiego zaczynające się od <i>L</i> zapisywało się jako zaczynające się od <i>Ł</i>).", "Lechosław": "<b>Lechosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Powstało poprzez dodanie do imienia <a href=\"https://pl.wikipedia.org/wiki/Lech_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lech</a> charakterystycznego dla staropolskich imion członu <i>-sław</i>.", "Lubomir": "<b>Lubomir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Lubo-</i> („miły, przyjemny, kochany”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło oznaczać „ten, który miłuje pokój”. Imię używane również w innych <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">krajach słowiańskich</a>.", "Lew": "<a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">Etymologia</a> nazw <i>lew</i> i <i>Panthera leo</i> nie jest jednoznacznie wyjaśniona. Słowo <i>leo</i> pochodzi od łacińskiego <i>leō, leōnis</i>, które z kolei wywodzi się ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">starogreckiego</a> <i>leōn</i>/λεων. Dalszych źródeł autorzy dopatrują się w języku hebrajskim i staroegipskim.", "Ludomir": "<b>Ludomir</b>, <b>Ludomer</b>, <b>Ludmar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Ludo-</i> („ludzie”) i <i>-mir</i> („pokój, spokój, dobro”). Być może oznaczało „ten, który ma szacunek ludzi” lub „ten, który zapewnia ludziom pokój”.", "Lee": "<b>Lee</b> – angielskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a>, występuje w odmianach „Lea” i „Leigh”, nadawane kobietom jak i mężczyznom.", "Lucjusz": "<b>Lucjusz</b>, <b>Łucjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do nielicznej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marek</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Kwintus\" target=\"_blank\" rel=\"noopener noreferrer\">Kwintus</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>), oznaczające „urodzony o brzasku” (<i>prima luce natus</i>).", "Luigi": "<b>Luigi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ルイージ&#32;<i>Ruīji</i>&#59; znany także jako <b>Super Luigi</b>) – fikcyjna postać z <a href=\"https://pl.wikipedia.org/wiki/Gra_komputerowa\" target=\"_blank\" rel=\"noopener noreferrer\">gier komputerowych</a>, stworzona przez <a href=\"https://pl.wikipedia.org/wiki/Japo%C5%84czycy\" target=\"_blank\" rel=\"noopener noreferrer\">japońskiego</a> twórcę gier <a href=\"https://pl.wikipedia.org/wiki/Shigeru_Miyamoto\" target=\"_blank\" rel=\"noopener noreferrer\">Shigeru Miyamoto</a>. Z pochodzenia jest <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włochem</a>.", "Ludwig": "<b>Ludwik</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze słowa oznaczającego „głośny”, „sławny”. Jest wersją rozwojową frankońskiego imienia Chlodwig. W pierwszym członie zawarty jest element hlut- (chlod-, chlud-) 'sławny', a w drugim -wik (-wig) 'walka, bitwa'.", "Liwiusz": "<b>Liwiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie; pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starorzymskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a>, które nosili mężczyźni należący do rodu Liwiuszów.", "Ładysław": "<b>Władysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię męskie pochodzenia słowiańskiego</a> złożone z dwu członów: <i>vlad-</i> („władać”) oraz <i>-slav</i> („sława”) i oznacza „ten, który włada sławą”, tj. „sławny, znamienity”.", "Lambert": "<b>Lambert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Upowszechniło się w średniowieczu po podboju Anglii przez Normanów wraz z rozpowszechnieniem kultu <a href=\"https://pl.wikipedia.org/wiki/Lambert_z_Maastricht\" target=\"_blank\" rel=\"noopener noreferrer\">św. Lamberta z Maastricht</a>.", "Lajos": "Lajos ściągnął klątwę na ród. Był raz u króla Pelopsa i uwiódł jego syna. Kiedy go jednak porzucił, chłopak popełnił samobójstwo. <a href=\"https://pl.wikipedia.org/wiki/Wyrocznia_delficka\" target=\"_blank\" rel=\"noopener noreferrer\">Wyrocznia delficka</a> przepowiedziała Lajosowi, że dziecko <a href=\"https://pl.wikipedia.org/wiki/Jokasta_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jokasty</a> zostanie jego zabójcą i ożeni się z własną matką. Gdy Jokasta powiła chłopca, któremu później nadano imię Edyp, Lajos kazał przebić gwoździem nogi syna i porzucić go w górach niedaleko Koryntu. Odnalezionego Edypa wychowała królewska para z <a href=\"https://pl.wikipedia.org/wiki/Korynt\" target=\"_blank\" rel=\"noopener noreferrer\">Koryntu</a> – <a href=\"https://pl.wikipedia.org/wiki/Polibos_(w%C5%82adca_Koryntu)\" target=\"_blank\" rel=\"noopener noreferrer\">Polibos</a> i <a href=\"https://pl.wikipedia.org/wiki/Meropa\" target=\"_blank\" rel=\"noopener noreferrer\">Meropa</a>. Przepowiednia spełniła się, kiedy Edyp spotkał na drodze Lajosa i przez sprzeczkę zabił swego ojca.", "Linus": "<b>Linus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, starorzymskie, mitologiczne, nosił je syn <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apollina</a> i <a href=\"https://pl.wikipedia.org/wiki/Terpsychora_(muza)\" target=\"_blank\" rel=\"noopener noreferrer\">Terpsychory</a>. Nie wyjaśniono znaczenia imienia.", "Lutosław": "<b>Lutosław</b>, <b>Lutsław</b>, <b>Lucsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Luto-</i> (\"srogi, okrutny, dziki\", por. <i><a href=\"https://pl.wikipedia.org/wiki/Luty\" target=\"_blank\" rel=\"noopener noreferrer\">luty</a></i>) i <i>-sław</i> (\"sława\"). Znaczenie imienia: \"słynący ze srogości\". Zdrobniale Lutek.", "Leander": "<b>Leander</b> – zlatynizowane <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się ze złożenia słów <i>leon</i> - „lew” i <i>andros</i> - „człowiek”. Jego patronem jest <a href=\"https://pl.wikipedia.org/wiki/Leander_z_Sewilli\" target=\"_blank\" rel=\"noopener noreferrer\">święty Leander</a>, biskup Sewilli.", "Łazarz": "<b>Łazarz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, od hebrajskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eleazar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eleazar</a> (co można przetłumaczyć jako <i>Ten, któremu Bóg pomaga</i>). Nosił je jeden z przyjaciół <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Chrystusa</a>, brat <a href=\"https://pl.wikipedia.org/wiki/Maria_z_Betanii\" target=\"_blank\" rel=\"noopener noreferrer\">Marii</a> i <a href=\"https://pl.wikipedia.org/wiki/Marta_z_Betanii\" target=\"_blank\" rel=\"noopener noreferrer\">Marty</a>. Imię to pojawia się również w Jezusowej <a href=\"https://pl.wikipedia.org/wiki/Przypowie%C5%9B%C4%87_o_bogaczu_i_%C5%81azarzu\" target=\"_blank\" rel=\"noopener noreferrer\">opowieści o bogaczu i Łazarzu</a>.", "Luis Miguel": "<b>Luis Miguel Gallego Basteri</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/19_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 kwietnia</a> <a href=\"https://pl.wikipedia.org/wiki/1970_w_muzyce\" target=\"_blank\" rel=\"noopener noreferrer\">1970</a> w <a href=\"https://pl.wikipedia.org/wiki/San_Juan\" target=\"_blank\" rel=\"noopener noreferrer\">San Juan</a>) – <a href=\"https://pl.wikipedia.org/wiki/Meksyk\" target=\"_blank\" rel=\"noopener noreferrer\">meksykański</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarz</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Został czterokrotnie uhonorowany <a href=\"https://pl.wikipedia.org/wiki/Latin_Grammy_Awards\" target=\"_blank\" rel=\"noopener noreferrer\">nagrodą Latin Grammy Awards</a> i pięciokrotnie <a href=\"https://pl.wikipedia.org/wiki/Nagroda_Grammy\" target=\"_blank\" rel=\"noopener noreferrer\">nagrodą Grammy</a>. Ma swoją gwiazdę w <a href=\"https://pl.wikipedia.org/wiki/Aleja_Gwiazd_w_Los_Angeles\" target=\"_blank\" rel=\"noopener noreferrer\">Hollywoodzkiej Alei Gwiazd</a>.", "Leoncjusz": "Do języka polskiego imię to zostało zapożyczone z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>, gdzie miało formę <i>Leontius</i>. Natomiast do łaciny dostało się z greki: Λεόντιος <i>Leóntios</i> było tam <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnieniem</a> różnych imion rozpoczynających się od członu Λεον- <i>Leon-</i>, a wywodzących się od wyrazu λέων <i>léōn</i> „lew”.", "Ludosław": "<b>Ludosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>.", "Laurencjusz": "<b>Laurencjusz</b> (łac. <i>Laurentius</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, genetycznie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognomen</a> utworzone od nazwy miasta Laurentum (<a href=\"https://pl.wikipedia.org/wiki/Lacjum\" target=\"_blank\" rel=\"noopener noreferrer\">Lacjum</a>). Laurentius to pierwotnie 'człowiek z Laurentum'. Wywodzi się od słowa oznaczającego „wieniec wawrzynowy”. Jego formę oboczną stanowi <a href=\"https://pl.wikipedia.org/wiki/Laurenty\" target=\"_blank\" rel=\"noopener noreferrer\">Laurenty</a>, a za spolszczenie uznawane jest polskie imię <a href=\"https://pl.wikipedia.org/wiki/Wawrzyniec\" target=\"_blank\" rel=\"noopener noreferrer\">Wawrzyniec</a>. Patronem imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Wawrzyniec_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Laurencjusz z Canterbury</a>.", "Leroy": "<b>Leroy</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>.", "Lubosław": "<b>Lubosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, nienotowane w średniowecznej Polsce i stanowiące najprawdopodobniej <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX-wieczny</a> <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a>, złożony z członów <i>Lubo-</i> („miły, przyjemny, kochany”) oraz <i>-sław</i> („sława”). Może oznaczać „ten, który miłuje sławę”.", "Leokadiusz": "<b>Leokadiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, utworzone z wyrazów pospolitych <i>laós (léos)</i>, oznaczającego <i>lud</i> oraz <i>kedos (kados)</i>, oznaczającego <i>troskę</i>. Imię to oznacza zatem <i>troszczący się o lud</i>.", "Ludomił": "<b>Ludomił</b>, <b>Ludmił</b> – męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego imienia</a> żeńskiego <a href=\"https://pl.wikipedia.org/wiki/Ludomi%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Ludomiła</a>, nienotowany w źródłach staropolskich.", "Lahiru": "Obszar ten podbity został w latach 731-729 p.n.e. przez króla <a href=\"https://pl.wikipedia.org/wiki/Tiglat-Pileser_III\" target=\"_blank\" rel=\"noopener noreferrer\">Tiglat-Pilesera III</a> (744-727 p.n.e.), który następnie przekazał go w zarządzanie gubernatorowi <a href=\"https://pl.wikipedia.org/wiki/Arrapha\" target=\"_blank\" rel=\"noopener noreferrer\">Arraphy</a>. Nie wiadomo dokładnie kiedy tereny te przekształcone zostały w asyryjską prowincję, ale jej powstanie na pewno wiązać się musiało z utworzeniem sąsiadujących z nią prowincji <a href=\"https://pl.wikipedia.org/wiki/Lubdu\" target=\"_blank\" rel=\"noopener noreferrer\">Lubda</a> i Szamasz-nasir. Najwcześniejsze informacje o prowincji Lahiru pochodzą z listu z czasów <a href=\"https://pl.wikipedia.org/wiki/Sargon_II\" target=\"_blank\" rel=\"noopener noreferrer\">Sargona II</a> (722-705 p.n.e.). Za rządów <a href=\"https://pl.wikipedia.org/wiki/Sennacheryb\" target=\"_blank\" rel=\"noopener noreferrer\">Sennacheryba</a> (704-681 p.n.e.) do prowincji tej przesiedlona została ludność z plemienia Jasubigallejczyków. W inskrypcjach tego samego króla zbuntowany chaldejski przywódca Szuzubu (<a href=\"https://pl.wikipedia.org/wiki/Muszezib-Marduk\" target=\"_blank\" rel=\"noopener noreferrer\">Muszezib-Marduk</a>) nazywany jest sługą gubernatora Lahiru. Gubernator Lahiru o imieniu Atar-ili sprawował w roku 673 p.n.e., za rządów <a href=\"https://pl.wikipedia.org/wiki/Asarhaddon\" target=\"_blank\" rel=\"noopener noreferrer\">Asarhaddona</a> (681-669 p.n.e.), urząd <i><a href=\"https://pl.wikipedia.org/wiki/Limmu\" target=\"_blank\" rel=\"noopener noreferrer\">limmu</a></i> (<a href=\"https://pl.wikipedia.org/wiki/Eponim\" target=\"_blank\" rel=\"noopener noreferrer\">eponima</a>). Prowincja wspominana jest też w listach z czasów panowania Asarhaddona i <a href=\"https://pl.wikipedia.org/wiki/Aszurbanipal\" target=\"_blank\" rel=\"noopener noreferrer\">Aszurbanipala</a> (669-627? p.n.e.). W 670 r. p.n.e. gubernator Lahiru, jego zastępca i dwóch innych podwładnych sprzedali wioskę eunuchowi następcy tronu z <a href=\"https://pl.wikipedia.org/wiki/Babilon\" target=\"_blank\" rel=\"noopener noreferrer\">Babilonu</a> (tj. eunuchowi <a href=\"https://pl.wikipedia.org/wiki/Szamasz-szuma-ukin\" target=\"_blank\" rel=\"noopener noreferrer\">Szamasz-szuma-ukina</a>). Inny podwładny gubernatora Lahiru pojawia się w dokumencie datowanym imieniem eponima Nabu-da’’inanni (czasy Aszurbanipala, po 648 r. p.n.e.). Prowincja Lahiru wzmiankowana jest również w jednej z list posiadłości z VII w. p.n.e.", "Ludger": "<b>Ludger, Ludgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie <i>Liutger</i> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>liut</i> (\"lud, ludzie\") i <i>ger</i> (\"dzida, włócznia\"), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a> <i>Liudger</i>. Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Ludger\" target=\"_blank\" rel=\"noopener noreferrer\">św. Ludger</a>, biskup miasta Minigardeford (późn. Monastyr, <i><a href=\"https://pl.wikipedia.org/wiki/M%C3%BCnster\" target=\"_blank\" rel=\"noopener noreferrer\">Münster</a></i>).", "Lewi": "Księga Rodzaju wspomina o Lewim przy okazji incydentu, do jakiego doszło w mieście <a href=\"https://pl.wikipedia.org/wiki/Sychem\" target=\"_blank\" rel=\"noopener noreferrer\">Sychem</a>. Jakub przybył do Sychem z zamiarem osiedlenia się. Pewnego dnia jego córka <a href=\"https://pl.wikipedia.org/wiki/Dina_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Dina</a> wybrała się do miasta. Została tam porwana i zgwałcona przez syna tamtejszego władcy Chamora, który nosił imię Sychem (tak jak miasto). Chamor, ojciec Sychema przybył do Jakuba i jego synów z przeprosinami. Tłumaczył mu, że jego syn zakochał się w Dinie i prosi o jej rękę. Obiecał zapłacić rekompensatę. Oprócz tego zaprosił rodzinę Jakuba, by osiedliła się w jego ziemi i by jego synowie wzięli sobie za żony mieszkanki Sychem.", "Łucjusz": "<b>Lucjusz</b>, <b>Łucjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do nielicznej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marek</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Kwintus\" target=\"_blank\" rel=\"noopener noreferrer\">Kwintus</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>), oznaczające „urodzony o brzasku” (<i>prima luce natus</i>).", "Lang": "Nazwa pochodzi od regionu w północnych <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> – Langhe.", "Laureano": "<b>Anthony „Tony” Laureano</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/25_stycznia\" target=\"_blank\" rel=\"noopener noreferrer\">25 stycznia</a> <a href=\"https://pl.wikipedia.org/wiki/1973\" target=\"_blank\" rel=\"noopener noreferrer\">1973</a>), znany również jako <b>El Angelito</b> – amerykański <a href=\"https://pl.wikipedia.org/wiki/Perkusja\" target=\"_blank\" rel=\"noopener noreferrer\">perkusista</a>, muzyk sesyjny <a href=\"https://pl.wikipedia.org/wiki/Portoryko\" target=\"_blank\" rel=\"noopener noreferrer\">portorykańskiego</a> pochodzenia. Naukę gry na instrumencie podjął w wieku 18 lat. W międzyczasie grał także na <a href=\"https://pl.wikipedia.org/wiki/Gitara_basowa\" target=\"_blank\" rel=\"noopener noreferrer\">gitarze basowej</a>. Tony Laureano znany jest przede wszystkim z występów w <a href=\"https://pl.wikipedia.org/wiki/Death_metal\" target=\"_blank\" rel=\"noopener noreferrer\">deathmetalowej</a> grupie muzycznej <a href=\"https://pl.wikipedia.org/wiki/Nile\" target=\"_blank\" rel=\"noopener noreferrer\">Nile</a>, której był członkiem w latach 2000-2004. W latach 2004–2005 i 2007-2008 koncertował wraz z norweskim zespołem <a href=\"https://pl.wikipedia.org/wiki/Black_metal\" target=\"_blank\" rel=\"noopener noreferrer\">blackmetalowym</a> <a href=\"https://pl.wikipedia.org/wiki/Dimmu_Borgir\" target=\"_blank\" rel=\"noopener noreferrer\">Dimmu Borgir</a>. Perkusista wystąpił wraz z grupą m.in. podczas objazdowego festiwalu <a href=\"https://pl.wikipedia.org/wiki/Ozzfest\" target=\"_blank\" rel=\"noopener noreferrer\">Ozzfest</a> w Stanach Zjednoczonych w 2004 roku. Zapis koncertów z udziałem Tony’ego Laureano znalazł się m.in. na płycie DVD formacji pt. <i><a href=\"https://pl.wikipedia.org/wiki/The_Invaluable_Darkness\" target=\"_blank\" rel=\"noopener noreferrer\">The Invaluable Darkness</a></i> (2008).", "Laura": "<b>Laura</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego. Pierwotnie oznaczało ono kobietę pochodzącą z <a href=\"https://pl.wikipedia.org/wiki/Laurentum\" target=\"_blank\" rel=\"noopener noreferrer\">Laurentum</a> koło Rzymu. Wiązane jest także z łacińskim słowem <i>laurus</i> oznaczającym <a href=\"https://pl.wikipedia.org/wiki/Wawrzyn\" target=\"_blank\" rel=\"noopener noreferrer\">wawrzyn</a>.", "Leoncio": "Do języka polskiego imię to zostało zapożyczone z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>, gdzie miało formę <i>Leontius</i>. Natomiast do łaciny dostało się z greki: Λεόντιος <i>Leóntios</i> było tam <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnieniem</a> różnych imion rozpoczynających się od członu Λεον- <i>Leon-</i>, a wywodzących się od wyrazu λέων <i>léōn</i> „lew”.", "Lord": "<a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">Etymologia</a> angielskiego słowa <i>lord</i> ma odwołania do języka staroangielskiego, w którym <i>hlaford</i> (wcześniej <i>hlaf-weard</i> – strażnik chleba) nawiązywał do <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskich</a> plemiennych zwyczajów, i oznaczał osobę odpowiedzialną za zaopatrzenie w żywność i jej podział. Żeński odpowiednik to <i>lady</i>.", "Lubomierz": "<b>Lubomir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Lubo-</i> („miły, przyjemny, kochany”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło oznaczać „ten, który miłuje pokój”. Imię używane również w innych <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">krajach słowiańskich</a>.", "Lemma": "<b>Forma słownikowa</b>, także: <b>forma hasłowa</b>, <b>lemma</b>, <b>lemat</b>, <b>hasło</b> – ta spośród <a href=\"https://pl.wikipedia.org/wiki/Forma_j%C4%99zykowa\" target=\"_blank\" rel=\"noopener noreferrer\">form</a> gramatycznych <a href=\"https://pl.wikipedia.org/wiki/Wyraz\" target=\"_blank\" rel=\"noopener noreferrer\">wyrazu</a> <a href=\"https://pl.wikipedia.org/wiki/Fleksja\" target=\"_blank\" rel=\"noopener noreferrer\">odmiennego</a>, która jest tradycyjnie wykorzystywana w <a href=\"https://pl.wikipedia.org/wiki/S%C5%82ownik\" target=\"_blank\" rel=\"noopener noreferrer\">słownikach</a> i reprezentuje tam w <a href=\"https://pl.wikipedia.org/wiki/Has%C5%82o_(informacja_naukowa)\" target=\"_blank\" rel=\"noopener noreferrer\">nagłówku</a> <a href=\"https://pl.wikipedia.org/wiki/Artyku%C5%82_has%C5%82owy\" target=\"_blank\" rel=\"noopener noreferrer\">artykułu hasłowego</a> cały wyraz ze wszystkimi jego formami. Forma ta stanowi niejako „umowną etykietę zbioru form” i decyduje o umiejscowieniu artykułu hasłowego w słowniku.", "Lea": "<b>Lea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> wywodzące się od hebrajskiego słowa לְאָה (le'ah) oznaczającego „zmęczony”. Może mieć także związek z akadyjskim słowem <i>littu</i> oznaczającym „krowa”. W <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">języku łacińskim</a> oznacza „lwicę”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> <a href=\"https://pl.wikipedia.org/wiki/Lea_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Lea</a> jest córką Labana i pierwszą żoną Jakuba.", "Lewin": "<b>Lewin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. W języku staroangielskim <i>Leofwine</i> (od <i>leof</i> \"przyjazny, lubiany, zgodny\" i <i>wine</i> \"przyjaciel\"), w starowysokoniemieckim <i>Liefwine</i>, <i>Leubwini</i> (od <i>liub</i> \"kochany\" i <i>wini</i> przyjaciel\"), w dialekcie dolnoreńskim <i>Lewin</i>, skąd trafiło do języka polskiego (zapisane w takiej formie już w średniowieczu). Imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Lewin_z_Gent\" target=\"_blank\" rel=\"noopener noreferrer\">św. Lewin</a>, irlandzki ksiądz zm. ok. 650 identyfikowany z anglosaskim misjonarzem działającym we <a href=\"https://pl.wikipedia.org/wiki/Fryzja_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Fryzji</a>, <a href=\"https://pl.wikipedia.org/wiki/Lebuin_z_Deventer\" target=\"_blank\" rel=\"noopener noreferrer\">św. Lebuinem</a> (zm. ok. 773). Obaj święci wspominani są w Kościele katolickim <a href=\"https://pl.wikipedia.org/wiki/12_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">12 listopada</a>.", "Leonida": "<b>Leonida</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Leonid\" target=\"_blank\" rel=\"noopener noreferrer\">Leonid</a>. Istnieje szereg świętych katolickich o tym imieniu.", "Larsen": "<b>Larsen</b> – popularne nazwisko norweskie (4 miejsce) i duńskie (7 miejsce), znaczy <i>syn Larsa</i> (tzn. <a href=\"https://pl.wikipedia.org/wiki/Laurencjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Laurentego</a>, Wawrzyńca). Szwedzkim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Larsson\" target=\"_blank\" rel=\"noopener noreferrer\">Larsson</a>.", "Ludmił": "<b>Ludomił</b>, <b>Ludmił</b> – męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego imienia</a> żeńskiego <a href=\"https://pl.wikipedia.org/wiki/Ludomi%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Ludomiła</a>, nienotowany w źródłach staropolskich.", "Larysa": "<b>Larysa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">antycznego</a> miasta <i>Larissa</i> (w świecie starożytnym istniało 8 <a href=\"https://pl.wikipedia.org/wiki/Larisa\" target=\"_blank\" rel=\"noopener noreferrer\">miast o tej nazwie</a>). W języku polskim imię rzadkie, natomiast częste w języku rosyjskim. Forma <i>Lara</i> stanowi rosyjskie zdrobnienie od Larysy.", "Lutomir": "<b>Lutomir</b>, <b>Lutomiar</b>, <b>Lutmiar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Luto-</i> (\"srogi, okrutny, dziki\", por. <i><a href=\"https://pl.wikipedia.org/wiki/Luty\" target=\"_blank\" rel=\"noopener noreferrer\">luty</a></i>) i <i>-mir</i> (\"pokój, spokój, dobro\").", "Leontyn": "<b>Leontyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>Leo</i> oznaczającego lwa. Nosiło je kilku <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty\" target=\"_blank\" rel=\"noopener noreferrer\">świętych</a> wczesnego kościoła katolickiego: św. Leontyn z Bragi, św. Leontyn z Saintes, św. Leontyn (męczennik za <a href=\"https://pl.wikipedia.org/wiki/Dioklecjan\" target=\"_blank\" rel=\"noopener noreferrer\">Dioklecjana</a>) i św. Leontyn z Cezarei.", "Lancelot": "Był synem króla Bana z Benoic, a więc księciem z urodzenia. W dzieciństwie został porwany przez czarodziejkę <a href=\"https://pl.wikipedia.org/wiki/Pani_Jeziora_(posta%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Vivianę</a>, która wychowywała go (według niektórych wersji mitu, była ona jego matką). Od 18. roku życia przebywał na dworze <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3l_Artur\" target=\"_blank\" rel=\"noopener noreferrer\">króla Artura</a>, gdzie (jeszcze przed przybyciem Artura), nadano mu imię Lancelot.", "Lewko": "W źródłach chrześcijańskich wymieniane jest imię żony Lewka – Swonka. Prawdopodobnie była wyraźnie młodsza od niego, bowiem ostatnia wzmianka o nim pochodzi z 1395, a o Swonce źródła wspominają także na początku lat 20. XV w. Mieli czterech synów: Jordana, Abrahama, Kanaana i Izraela, a także jedną córkę – Gołdę. Z czasem Lewko wybudował przy ulicy Żydowskiej dom. Usytuował go na <a href=\"https://pl.wikipedia.org/wiki/Komasacja\" target=\"_blank\" rel=\"noopener noreferrer\">scalonych</a> uprzednio gruntach, tuż przy <a href=\"https://pl.wikipedia.org/wiki/Mury_miejskie_w_Krakowie\" target=\"_blank\" rel=\"noopener noreferrer\">murze miejskim</a>, w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Synagoga_Garncarska_w_Krakowie\" target=\"_blank\" rel=\"noopener noreferrer\">synagogi</a>. Nawet wiele lat po śmierci Lewka domostwo było określane jako <i>domus Levconis</i>.", "Litawor": "<b>Litawor</b> był przydomkiem rodu magnackiego <a href=\"https://pl.wikipedia.org/wiki/Karol_Litawor_Chreptowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Chreptowiczów</a>, po raz pierwszy użytym przez podskarbiego dwornego litewskiego Iwana (Iwaszkę, †<a href=\"https://pl.wikipedia.org/wiki/1513\" target=\"_blank\" rel=\"noopener noreferrer\">1513</a>), syna Bohdana, a pochodzącym od niemieckiego słowa <i>Litauer</i>, oznaczającego \"<a href=\"https://pl.wikipedia.org/wiki/Litwini\" target=\"_blank\" rel=\"noopener noreferrer\">Litwina</a>\".", "Lorens": "<b>Lorens</b> (<b>Lr</b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>lawrencium</i>), dawniej oznaczany także <b>Lw</b> – syntetyczny <a href=\"https://pl.wikipedia.org/wiki/Pierwiastek_chemiczny\" target=\"_blank\" rel=\"noopener noreferrer\">pierwiastek chemiczny</a>, nieposiadający stabilnych <a href=\"https://pl.wikipedia.org/wiki/Izotopy\" target=\"_blank\" rel=\"noopener noreferrer\">izotopów</a> i niewystępujący w przyrodzie. Nazwa pochodzi od nazwiska fizyka <a href=\"https://pl.wikipedia.org/wiki/Ernest_Lawrence\" target=\"_blank\" rel=\"noopener noreferrer\">Ernesta O. Lawrence’a</a>.", "Lutogniew": "<b>Lutogniew</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Luto-</i> („srogi, okrutny, dziki”, por. <i><a href=\"https://pl.wikipedia.org/wiki/Luty\" target=\"_blank\" rel=\"noopener noreferrer\">luty</a></i>) i <i>-gniew</i>. Znaczenie imienia: „srogi w gniewie”. Imię w tej postaci wystąpiło w 1212.", "Lir": "<b>Lir</b> (\"morze\") – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_celtycka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii celtyckiej</a> bóg morza. Jego rodzicami byli <a href=\"https://pl.wikipedia.org/wiki/Danu\" target=\"_blank\" rel=\"noopener noreferrer\">Danu</a> i <a href=\"https://pl.wikipedia.org/wiki/Beli\" target=\"_blank\" rel=\"noopener noreferrer\">Beli</a>, a dziećmi (wszystkie ze związku z <a href=\"https://pl.wikipedia.org/wiki/Penarddun\" target=\"_blank\" rel=\"noopener noreferrer\">Penarddun</a> - <a href=\"https://pl.wikipedia.org/wiki/Manannan\" target=\"_blank\" rel=\"noopener noreferrer\">Manannan mac Lir</a>, <a href=\"https://pl.wikipedia.org/wiki/Bran_the_Blessed\" target=\"_blank\" rel=\"noopener noreferrer\">Bran</a> i <a href=\"https://pl.wikipedia.org/wiki/Branwen\" target=\"_blank\" rel=\"noopener noreferrer\">Branwen</a>. Jego tożsamość z Learem/Lirem, ojcem dzieci zamienionych według legendy \"<a href=\"https://pl.wikipedia.org/wiki/Dzieci_Lira\" target=\"_blank\" rel=\"noopener noreferrer\">Dzieci Lira</a>\" - \"Clann Lir\" (\"Children of Lir\") w łabędzie przez ciotkę macochę nie jest do końca pewna. Do czwórki tych dzieci należała <a href=\"https://pl.wikipedia.org/wiki/Finola_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Fionnuala</a>. (Imię jej matki to: \"Aoibh\" a jej siostry - czarownicy macochy - to: \"Aoife\", imiona trzech braci <a href=\"https://pl.wikipedia.org/wiki/Finola_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Fionnuali</a> to: Aodh, Fiachra i Conn).", "L": "<b>L</b> (<i>el</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>l</b>) – dwunasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, piętnasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Oznacza zwykle w danym języku <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę płynną boczną</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a>].", "Luk": "Na statkach towarowych nazwy luków pochodzą od numerów znajdujących się pod nimi <a href=\"https://pl.wikipedia.org/wiki/%C5%81adownia\" target=\"_blank\" rel=\"noopener noreferrer\">ładowni</a>.", "Lai": "<b>Lai</b> – starofrancuska forma <a href=\"https://pl.wikipedia.org/wiki/Pie%C5%9B%C5%84_(gatunek_literacki)\" target=\"_blank\" rel=\"noopener noreferrer\">pieśni lirycznej</a>, najczęściej o tematyce miłosnej, wywodząca się z pieśni <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckich</a>. Uprawiano ją z zamiłowaniem w <a href=\"https://pl.wikipedia.org/wiki/Bretania\" target=\"_blank\" rel=\"noopener noreferrer\">Bretanii</a>, z typowym dla <a href=\"https://pl.wikipedia.org/wiki/Truwerzy\" target=\"_blank\" rel=\"noopener noreferrer\">truwerów</a> wykonywaniem z towarzystwem instrumentu.", "Lasota": "<b>Lasota</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Wywodzi się od słowa \"las\" i oznacza \"tego, który żyje w lesie\". Podobne znaczenie ma łacińskie imię <a href=\"https://pl.wikipedia.org/wiki/Sylwester\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwester</a>, dlatego imię Lasota uważane jest często za polskie tłumaczenie tego imienia. Imię Lasota pojawiło się w polskich zapisach już w 1198 roku i miało większy zasięg niż Sylwester (imię notowane w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> od 1220 roku), dlatego można sądzić, że imiona te powstały niezależnie od siebie. Imię to stało się podstawą dla nazwiska Lasota. Nazwiska Lasota z kolei nie można mylić z Lassota – które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a> Lasstosa i oznacza barkę do transportu drewna.", "Ly": "<b>Ly</b> (<i>elly</i>, <i>ejj</i>, <i>ellipszilon</i>) – <a href=\"https://pl.wikipedia.org/wiki/Dwuznak\" target=\"_blank\" rel=\"noopener noreferrer\">dwuznak</a> w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C4%99gierski\" target=\"_blank\" rel=\"noopener noreferrer\">języku węgierskim</a>. Wymawia się podobnie jak <i>j</i>, chociaż historycznie <i>ly</i> i <i>j</i> oznaczały dwa różne dźwięki.", "Liberat": "<b>Liberat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"wyzwolony\". Istnieje kilku świętych patronów tego imienia.", "Lilia": "<b>Lilia</b> – imię żeńskie pochodzenia łacińskiego. Od tego imienia powstało inne, w dwóch wariantach pisowni: <a href=\"https://pl.wikipedia.org/wiki/Liliana\" target=\"_blank\" rel=\"noopener noreferrer\">Liliana</a> i <a href=\"https://pl.wikipedia.org/wiki/Liliana\" target=\"_blank\" rel=\"noopener noreferrer\">Lilianna</a>.", "Lutobor": "<b>Lutobor</b>, <b>Litobor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Luto-</i> („srogi, okrutny, dziki”, por. <i><a href=\"https://pl.wikipedia.org/wiki/Luty\" target=\"_blank\" rel=\"noopener noreferrer\">luty</a></i>) i <i>-bor</i> („walczyć, zmagać się”). Znaczenie imienia: „srogi w walce”. Źródła polskie zawierają dwie postaci imienia w średniowieczu: Lutobor (w 1186) i Litobor (między 1252 a 1288).", "Liberiusz": "<b>Liberiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>liber</i> oznaczającego wolny.", "Linda": "<b>Linda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Istnieje kilka koncepcji jego pochodzenia. Może wywodzić się od portugalskiego słowa <i>linda</i> oznaczającego \"piękna\", może być zdrobnieniem takich imion jak <i>Belinda</i> lub <i>Melinda</i> lub też pochodzić od germańskiego pierwiastka językowego <i>linden</i> znaczącego \"miękki\", \"czuły\". Imię to może też wywodzić się z języków germańskich lub estońskiego (według mitologii imię to nosiła żona Kaleva – praojca wszystkich ludów zachodniofińskich).", "Lupus": "<b>Lupus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzi z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> i oznacza tyle co <i>wilk</i>. Spotyka się różną pisownię: <i>Loupus</i> czy <i>Luppus</i>, odpowiednikami w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">języku francuskim</a> jest <i>Loup</i>, <i>Lou</i> i <i>Loubes</i>, zaś w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskim</a> <i>Lope</i> i <i>Lobo</i>, a <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskim</a> <i>Lupo</i>. <a href=\"https://pl.wikipedia.org/wiki/Patron_(chrze%C5%9Bcija%C5%84stwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Patronami</a> imienia są <a href=\"https://pl.wikipedia.org/wiki/Lupus_z_Troyes\" target=\"_blank\" rel=\"noopener noreferrer\">Lupus</a> - biskup Troyes <a href=\"https://pl.wikipedia.org/wiki/Wspomnienie_liturgiczne\" target=\"_blank\" rel=\"noopener noreferrer\">wspominany</a> <a href=\"https://pl.wikipedia.org/wiki/29_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">29 lipca</a> i wspominany <a href=\"https://pl.wikipedia.org/wiki/2_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">2 września</a> bł. <a href=\"https://pl.wikipedia.org/wiki/Lupus_Thomas\" target=\"_blank\" rel=\"noopener noreferrer\">Lupus Thomas</a>.", "Legrand": "<b>Legrand</b> – <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuska</a> grupa przemysłowa historycznie założona w <a href=\"https://pl.wikipedia.org/wiki/Limoges\" target=\"_blank\" rel=\"noopener noreferrer\">Limoges</a> w <a href=\"https://pl.wikipedia.org/wiki/Limousin\" target=\"_blank\" rel=\"noopener noreferrer\">Limousin</a>, specjalizująca się w produktach do instalacji elektrycznych i sieci informatycznych.", "Liliana": "<b>Liliana</b>, Lilianna – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <a href=\"https://pl.wikipedia.org/wiki/Lilia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">lilia</a>. Liliana, Lilianna <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/14_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">14 lutego</a> i <a href=\"https://pl.wikipedia.org/wiki/4_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">4 września</a>.", "Lena": "<b>Lena</b> – imię żeńskie, popularne w krajach słowiańskich i skandynawskich; usamodzielnione zdrobnienie od greckiego Ἑλένη (pol. <a href=\"https://pl.wikipedia.org/wiki/Helena_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Helena</a>) lub Μαγδαληνή (pol. <a href=\"https://pl.wikipedia.org/wiki/Magdalena\" target=\"_blank\" rel=\"noopener noreferrer\">Magdalena</a>). W Polsce forma o brzmieniu <i>Lena</i> jest notowana od 1418 roku, jako pochodna żeńska imienia <a href=\"https://pl.wikipedia.org/wiki/Helena_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Helena</a> lub męska – <a href=\"https://pl.wikipedia.org/wiki/Leonard\" target=\"_blank\" rel=\"noopener noreferrer\">Lenarda</a> (może także <a href=\"https://pl.wikipedia.org/wiki/Leonid\" target=\"_blank\" rel=\"noopener noreferrer\">Lenida</a>, <a href=\"https://pl.wikipedia.org/wiki/Leon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Leona</a>). W Polsce można się spotkać również ze zdrabnianiem w ten sposób imion <a href=\"https://pl.wikipedia.org/wiki/Milena_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milena</a> i <a href=\"https://pl.wikipedia.org/wiki/Marlena\" target=\"_blank\" rel=\"noopener noreferrer\">Marlena</a>, <a href=\"https://pl.wikipedia.org/wiki/Eleonora\" target=\"_blank\" rel=\"noopener noreferrer\">Eleonora</a> i <a href=\"https://pl.wikipedia.org/wiki/Leonia\" target=\"_blank\" rel=\"noopener noreferrer\">Leonia</a>.", "Laban": "Według <a href=\"https://pl.wikipedia.org/wiki/Midrasz\" target=\"_blank\" rel=\"noopener noreferrer\">midrasza</a> <i>Sefer ha-Jaszar</i> Laban miał żonę imieniem Adina, a jego synowie nosili imiona Beor, Alub i Murasz.", "Lary": "Etymologia tego słowa pozostaje niejasna. Wyróżniano ogółem następujące odmiany larów:", "Lidia": "<b>Lidia</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Λυδία – mieszkanka <a href=\"https://pl.wikipedia.org/wiki/Lidia_(kraina)\" target=\"_blank\" rel=\"noopener noreferrer\">Lidii</a>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, w późniejszym czasie przejęte przez <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymian</a>.", "Lucyna": "<b>Lucyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Oznacza z łac. <i>lucina</i> – niosąca światło, narodziny (lucinus, -a, -um 'świetlisty'). Patronką imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Lucyna\" target=\"_blank\" rel=\"noopener noreferrer\">św. Lucyna</a> z I lub III wieku. Wywodzi się od imienia bogini światła i narodzin. Powiązanym imieniem może być germańska „Lucinda”, pochodząca od imienia „Lucia” (<a href=\"https://pl.wikipedia.org/wiki/%C5%81ucja\" target=\"_blank\" rel=\"noopener noreferrer\">Łucja</a>).", "Łucja": "<b>Łucja</b>, <b>Lucja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Łucjusz lub Lucjusz</a>. Oznacza <i>dziewczynkę narodzoną o wschodzie słońca</i>.", "Leokadia": "<b>Leokadia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeńska wersja męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Leokadiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Leokadiusz</a>. Oznacza „troszcząca się o lud”. W Polsce rozpowszechniło się w XIX wieku dzięki powieściom <a href=\"https://pl.wikipedia.org/wiki/St%C3%A9phanie_F%C3%A9licit%C3%A9_de_Genlis\" target=\"_blank\" rel=\"noopener noreferrer\">Stéphanie Félicité de Genlis</a>. W XIX wieku było nowym i rzadkim imieniem wśród drobnej szlachty <a href=\"https://pl.wikipedia.org/wiki/Przasnysz\" target=\"_blank\" rel=\"noopener noreferrer\">przasnyskiej</a>, nadal obecne wśród starszego pokolenia, szczególnie na wschodzie kraju.", "Lilianna": "<b>Liliana</b>, Lilianna – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <a href=\"https://pl.wikipedia.org/wiki/Lilia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">lilia</a>. Liliana, Lilianna <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/14_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">14 lutego</a> i <a href=\"https://pl.wikipedia.org/wiki/4_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">4 września</a>.", "Luiza": "<b>Luiza</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ludwik\" target=\"_blank\" rel=\"noopener noreferrer\">Ludwik</a>. Zobacz też: <a href=\"https://pl.wikipedia.org/wiki/Ludwika\" target=\"_blank\" rel=\"noopener noreferrer\">Ludwika</a>.", "Ludwika": "<b>Ludwika</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ludwik\" target=\"_blank\" rel=\"noopener noreferrer\">Ludwik</a>, pochodzenia germańskiego. Średniowieczne źródła potwierdzają wystąpienie w języku polskim w 1476.", "Liwia": "<b>Liwia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie powstałe w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>; pierwotnie oznaczało „należąca do rodu Liwiuszów”.", "Ludmiła": "<b>Ludomiła</b>, <b>Ludmiła</b>, <b>Ludzimiła</b>, <b>Ludźmiła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, używane też na pozostałym obszarze słowiańskim, złożone z członów <i>Ludo-</i> (\"ludzie, ludziom\") i <i>-miła</i> (\"miła\"). Znaczenie: \"miła ludziom\". Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Ludomi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Ludomił</a>, Ludmił. Stało się popularne w XIX wieku, dzięki romansowi \"Żelisław i Ludmiła\" <a href=\"https://pl.wikipedia.org/wiki/Leon_Potocki_(1799%E2%80%931864)\" target=\"_blank\" rel=\"noopener noreferrer\">Leona Potockiego</a> ogłoszonego w <a href=\"https://pl.wikipedia.org/wiki/Tygodnik_Polski\" target=\"_blank\" rel=\"noopener noreferrer\">Tygodniku Polskim</a> w 1816 roku.", "Lilla": "<b>Lilla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> wyrazu <i>lilium</i> - \"lilia\". Spopularyzował je <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusz Słowacki</a> w <i><a href=\"https://pl.wikipedia.org/wiki/Lilla_Weneda\" target=\"_blank\" rel=\"noopener noreferrer\">Lilli Wenedzie</a></i>.", "Longina": "<b>Longina</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Longin\" target=\"_blank\" rel=\"noopener noreferrer\">Longin</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrazu <i>longus</i> oznaczającego „długi”. Patronem tego imienia jest m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Longin_z_Cezarei_Kapadockiej\" target=\"_blank\" rel=\"noopener noreferrer\">Longin z Cezarei Kapadockiej</a>.", "Lucja": "<b>Łucja</b>, <b>Lucja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Łucjusz lub Lucjusz</a>. Oznacza <i>dziewczynkę narodzoną o wschodzie słońca</i>.", "Leonarda": "<b>Leonarda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińsko</a>–<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Leonard\" target=\"_blank\" rel=\"noopener noreferrer\">Leonard</a>. Pierwszy człon imienia stanowi wczesna pożyczka germańska z łaciny („lew” – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>lēwo</i>, <i>lěwo</i>; zachodniofrankońska, zromanizowana forma <i>leon</i>), natomiast drugi człon to stwniem. <i>hart</i> – „mocny, dzielny”.", "Livia": "<b>Liwia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie powstałe w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>; pierwotnie oznaczało „należąca do rodu Liwiuszów”.", "Ligia": "<b>Ligia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>ligus</i> oznaczającego czysty głos.", "Leontyna": "<b>Leontyna</b> – żeński odpowiednik greckiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Leontyn\" target=\"_blank\" rel=\"noopener noreferrer\">Leontyn</a>.", "Lisa": "<b>Lisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Komputer_osobisty\" target=\"_blank\" rel=\"noopener noreferrer\">komputer osobisty</a> zaprojektowany przez <a href=\"https://pl.wikipedia.org/wiki/Apple_Inc.\" target=\"_blank\" rel=\"noopener noreferrer\">Apple Computer</a> we wczesnych latach 80. XX wieku. Projekt komputera Lisa został zapoczątkowany w 1978 roku i powoli przeobraził się w komputer osobisty z <a href=\"https://pl.wikipedia.org/wiki/GUI\" target=\"_blank\" rel=\"noopener noreferrer\">graficznym interfejsem użytkownika</a> (GUI). Około roku 1982, <a href=\"https://pl.wikipedia.org/wiki/Steve_Jobs\" target=\"_blank\" rel=\"noopener noreferrer\">Steve Jobs</a> został wyrzucony z projektu Lisa i przyłączył się do <a href=\"https://pl.wikipedia.org/wiki/Macintosh\" target=\"_blank\" rel=\"noopener noreferrer\">Macintosha</a>. Wbrew powszechnej opinii, Macintosh nie wywodzi się bezpośrednio od Lisy, choć istnieje wiele oczywistych podobieństw pomiędzy tymi systemami. Premiera Lisy miała miejsce 19 stycznia 1983 roku.", "Leonia": "<b>Leonia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Leon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Leon</a>.", "Lubomira": "<b>Lubomira</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Lubomir_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lubomir</a>/<a href=\"https://pl.wikipedia.org/wiki/Lubomir_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lubomirz</a>, nienotowany w źródłach staropolskich. Znaczenie imienia: „miłująca pokój”.", "Letycja": "<b>Letycja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> (od nazwy rodu <i>Laetitia</i>), oznacza <i>piękno, wesołość, wdzięk</i>. Na cześć św. Letycji odbywa się co roku we wrześniu kilkudniowe święto w hiszpańskim <a href=\"https://pl.wikipedia.org/wiki/Ayerbe\" target=\"_blank\" rel=\"noopener noreferrer\">Ayerbe</a>.", "Layla": "<b>Leila</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;ليلى&#8206;) – używane na całym świecie arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">języków semickich</a>, od <a href=\"https://pl.wikipedia.org/wiki/Alternacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">rdzenia trójspółgłoskowego</a>: <a href=\"https://pl.wikipedia.org/wiki/L%C4%81m\" target=\"_blank\" rel=\"noopener noreferrer\"><b>L</b></a>-<a href=\"https://pl.wikipedia.org/wiki/Y%C4%81%CA%BE\" target=\"_blank\" rel=\"noopener noreferrer\"><b>J</b></a>-<a href=\"https://pl.wikipedia.org/wiki/L%C4%81m\" target=\"_blank\" rel=\"noopener noreferrer\"><b>L</b></a> (&#8207;ليل&#8206;, rdzeń wspólny z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> <i><a href=\"https://pl.wikipedia.org/wiki/Lilith\" target=\"_blank\" rel=\"noopener noreferrer\">Lilith</a></i>) i oznaczające „noc”; z czasem nabrało znaczenia „urodzona w nocy”, „ciemnowłosa piękność” lub „ciemna piękność”, w innych językach także jako <i>Lejla</i>, <i>Leyla</i>, <i>Layla</i>, <i>Laila</i>.", "Lesława": "<b>Lesława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Les%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Lesław</a> pochodzenia literackiego, powstałego w XIX wieku na wzór staropolskich imion złożonych.", "Lukrecja": "<b>Lukrecja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Lukrecjuszów</i>.", "Leyla": "<b>Leila</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;ليلى&#8206;) – używane na całym świecie arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">języków semickich</a>, od <a href=\"https://pl.wikipedia.org/wiki/Alternacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">rdzenia trójspółgłoskowego</a>: <a href=\"https://pl.wikipedia.org/wiki/L%C4%81m\" target=\"_blank\" rel=\"noopener noreferrer\"><b>L</b></a>-<a href=\"https://pl.wikipedia.org/wiki/Y%C4%81%CA%BE\" target=\"_blank\" rel=\"noopener noreferrer\"><b>J</b></a>-<a href=\"https://pl.wikipedia.org/wiki/L%C4%81m\" target=\"_blank\" rel=\"noopener noreferrer\"><b>L</b></a> (&#8207;ليل&#8206;, rdzeń wspólny z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> <i><a href=\"https://pl.wikipedia.org/wiki/Lilith\" target=\"_blank\" rel=\"noopener noreferrer\">Lilith</a></i>) i oznaczające „noc”; z czasem nabrało znaczenia „urodzona w nocy”, „ciemnowłosa piękność” lub „ciemna piękność”, w innych językach także jako <i>Lejla</i>, <i>Leyla</i>, <i>Layla</i>, <i>Laila</i>.", "Ludomira": "<b>Ludomira</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ludomir\" target=\"_blank\" rel=\"noopener noreferrer\">Ludomir</a>, nienotowany w źródłach staropolskich.", "Leona": "<b>Leona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Leon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Leon</a>, które w starożytnej <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Grecji</a> funkcjonowało jako zdrobnienie imion dwuczłonowych, zaczynających się lub kończących (jak <a href=\"https://pl.wikipedia.org/wiki/Pantaleon\" target=\"_blank\" rel=\"noopener noreferrer\">Pantaleon</a>) członem <i>λεων (leon)</i>, pochodzącym albo od słowa oznaczającego po grecku \"lud\", albo \"lew\". Już od czasów starożytnych jednak powszechnie uważano to imię za oznaczające \"lew\". Imię to pojawiło się także u <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymian</a>, bądź jako zapożyczenie z <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Grecji</a>, bądź niezależnie.", "Ludwina": "<b>Ludwina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od starogermańskiego imienia <i>Luitwine</i>. Można je tłumaczyć jako „przyjaciółka ludzi” bądź „lubiąca duże zgromadzenia ludzi”. Imię to bywa błędnie kojarzone jako inna forma imienia <a href=\"https://pl.wikipedia.org/wiki/Ludwika\" target=\"_blank\" rel=\"noopener noreferrer\">Ludwika</a>.", "Lolita": "<b>Lolita</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, zdrobnienie od imienia <a href=\"https://pl.wikipedia.org/wiki/Dolores_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dolores</a>. Po publikacji książki <a href=\"https://pl.wikipedia.org/wiki/Vladimir_Nabokov\" target=\"_blank\" rel=\"noopener noreferrer\">Vladimira Nabokova</a>, od imienia głównej jej bohaterki utworzono rzeczownik <i>lolita</i>, wykorzystywany najczęściej w przemyśle <a href=\"https://pl.wikipedia.org/wiki/Erotyka_(sztuka)\" target=\"_blank\" rel=\"noopener noreferrer\">erotycznym</a> i <a href=\"https://pl.wikipedia.org/wiki/Pornografia\" target=\"_blank\" rel=\"noopener noreferrer\">pornograficznym</a> na określenie młodej lub niepełnoletniej dziewczyny, potrafiącej wykorzystać swoje wdzięki i umiejętnie okręcić sobie wokół palca mężczyzn.", "Laurencja": "<b>Laurencja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> <a href=\"https://pl.wikipedia.org/wiki/Laurencjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Laurencjusz</a> i <a href=\"https://pl.wikipedia.org/wiki/Wawrzyniec\" target=\"_blank\" rel=\"noopener noreferrer\">Wawrzyniec</a>. Patronką tego imienia jest św. Laurencja, towarzyszka św. Palacjaty, oraz bł. <a href=\"https://pl.wikipedia.org/wiki/Laurencja_Garasimiw\" target=\"_blank\" rel=\"noopener noreferrer\">Laurencja Garasimiw</a>, towarzyszka bł. <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj_Czarnecki\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaja Czarneckiego</a>.", "Lucjana": "<b>Lucjana</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Lucjan\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjan</a>, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">języka łacińskiego</a>. Oboczna forma imienia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ucjana\" target=\"_blank\" rel=\"noopener noreferrer\">Łucjana</a>.", "Lubomiła": "<b>Lubomiła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię żeńskie</a> złożone z członów Lub- („miła, przyjemna, kochana”) i -miła („miła, przyjemna, kochana”).", "Loretta": "<b>Loreta</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielski</a> odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Laura\" target=\"_blank\" rel=\"noopener noreferrer\">Laura</a>. Forma powstała przez redukcję <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> zdrobnienia tego imienia do <i>Lauretta</i>.", "Ludgarda": "<b>Ludgarda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starogermańskiego</a>. Wywodzi się od słów <i>liut</i> i <i>gard</i>. Oznacza „ochronę ludu”.", "Ludomiła": "<b>Ludomiła</b>, <b>Ludmiła</b>, <b>Ludzimiła</b>, <b>Ludźmiła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, używane też na pozostałym obszarze słowiańskim, złożone z członów <i>Ludo-</i> (\"ludzie, ludziom\") i <i>-miła</i> (\"miła\"). Znaczenie: \"miła ludziom\". Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Ludomi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Ludomił</a>, Ludmił. Stało się popularne w XIX wieku, dzięki romansowi \"Żelisław i Ludmiła\" <a href=\"https://pl.wikipedia.org/wiki/Leon_Potocki_(1799%E2%80%931864)\" target=\"_blank\" rel=\"noopener noreferrer\">Leona Potockiego</a> ogłoszonego w <a href=\"https://pl.wikipedia.org/wiki/Tygodnik_Polski\" target=\"_blank\" rel=\"noopener noreferrer\">Tygodniku Polskim</a> w 1816 roku.", "Lilit": "<b>Lilith</b> – w folklorze żydowskim upiorzyca groźna dla kobiet w ciąży i niemowląt w pierwszych tygodniach ich życia; uważana za pierwszą żonę biblijnego <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adama</a>, wywodząca się najprawdopodobniej z tradycji <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">mezopotamskiej</a>.", "Leopolda": "<b>Leopolda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Leopold\" target=\"_blank\" rel=\"noopener noreferrer\">Leopold</a>, które wywodzi się od słowa oznaczającego \"lud\".", "Lilija": "<b>Lelija</b> - ludowa <a href=\"https://pl.wikipedia.org/wiki/Melodia\" target=\"_blank\" rel=\"noopener noreferrer\">melodia</a> <a href=\"https://pl.wikipedia.org/wiki/Dudy\" target=\"_blank\" rel=\"noopener noreferrer\">dudziarska</a> pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Wielkopolska\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkopolski</a>. W kraju znana jest lepiej w opracowaniu <a href=\"https://pl.wikipedia.org/wiki/Jerzy_Krzemi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Jerzego Krzemińskiego</a>, który użył jej w piosence <i>Te opolskie dziouchy</i> napisanej dla zespołu <a href=\"https://pl.wikipedia.org/wiki/No_To_Co\" target=\"_blank\" rel=\"noopener noreferrer\">No To Co</a>. Ze względu na tę <a href=\"https://pl.wikipedia.org/wiki/Aran%C5%BCacja\" target=\"_blank\" rel=\"noopener noreferrer\">aranżację</a>, melodię często błędnie uważa się za <a href=\"https://pl.wikipedia.org/wiki/%C5%9Al%C4%85sk\" target=\"_blank\" rel=\"noopener noreferrer\">śląską</a>. Piosenka ma 2 znane teksty: wielkopolski i śląski.", "Loreta": "<b>Loreta</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielski</a> odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Laura\" target=\"_blank\" rel=\"noopener noreferrer\">Laura</a>. Forma powstała przez redukcję <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> zdrobnienia tego imienia do <i>Lauretta</i>.", "Lawinia": "<b>Lawinia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> Lavinia) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „kobieta pochodząca z miasta Lawinium w Lacjum”. W <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a> <a href=\"https://pl.wikipedia.org/wiki/Lawinia_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Lawinia</a> była córką króla Latynusa i żoną Eneasza, który założył miasto nazwane przez siebie na cześć żony <i>Lawinium</i>.", "Lalita": "<b>Lalita Tripurasundari</b> (<i>Piękna Bogini Trzech Miast</i>) – główna bogini tantrycznej tradycji hinduistycznej <a href=\"https://pl.wikipedia.org/wiki/%C5%9Ariwidja\" target=\"_blank\" rel=\"noopener noreferrer\">śriwidja</a>, tantryczna forma bogini <a href=\"https://pl.wikipedia.org/wiki/Lakszmi\" target=\"_blank\" rel=\"noopener noreferrer\">Lakszmi</a> (Śri).", "Lechosława": "<b>Lechosława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Lechos%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Lechosław</a>, utworzonego w XIX wieku na wzór dwuczłonowych imion staropolskich.", "Lilith": "<b>Lilith</b> – w folklorze żydowskim upiorzyca groźna dla kobiet w ciąży i niemowląt w pierwszych tygodniach ich życia; uważana za pierwszą żonę biblijnego <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adama</a>, wywodząca się najprawdopodobniej z tradycji <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">mezopotamskiej</a>.", "Leopoldyna": "<b>Leopoldyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Leopold\" target=\"_blank\" rel=\"noopener noreferrer\">Leopold</a>.", "Lucylla": "<b>Lucyla</b>, <b>Lucylla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa <i>lux</i>, czyli \"światło\", odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Lucyliusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lucyliusz</a>. Jego patronką jest św. Lucyla, męczennica.", "Leandra": "<b>Leandra</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Leander_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Leander</a>, występuje także wariant Leondra.", "Lutosława": "<b>Lutosława</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Lutos%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Lutosław</a>, nienotowana w źródłach staropolskich. Znaczenie imienia: \"sławna ze srogości\".", "Luzia": "<b>Luzia</b> – nazwa szkieletu <a href=\"https://pl.wikipedia.org/wiki/Paleoindianie\" target=\"_blank\" rel=\"noopener noreferrer\">paleoindiańskiej</a> kobiety, pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Paleolit_g%C3%B3rny\" target=\"_blank\" rel=\"noopener noreferrer\">paleolitu górnego</a>. Jeden z najstarszych szkieletów paleoindiańskich odnalezionych na terenie obu <a href=\"https://pl.wikipedia.org/wiki/Ameryka\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryk</a>. Szkielet został odkryty w 1975 roku na <a href=\"https://pl.wikipedia.org/wiki/Stanowisko_archeologiczne\" target=\"_blank\" rel=\"noopener noreferrer\">stanowisku archeologicznym</a> Lapa Vermelha w <a href=\"https://pl.wikipedia.org/wiki/Lagoa_Santa_(Minas_Gerais)\" target=\"_blank\" rel=\"noopener noreferrer\">Lagoa Santa</a> (<a href=\"https://pl.wikipedia.org/wiki/Brazylia\" target=\"_blank\" rel=\"noopener noreferrer\">Brazylia</a>) przez <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuską</a> archeolog Annette Laming-Emperaire.", "Lyra": "<b>Lyra</b> – rzadkie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/P%C5%82e%C4%87_%C5%BCe%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a>, imię w języku angielskim oznacza <a href=\"https://pl.wikipedia.org/wiki/Lutnia\" target=\"_blank\" rel=\"noopener noreferrer\">Lutnię</a>, <a href=\"https://pl.wikipedia.org/wiki/Lira\" target=\"_blank\" rel=\"noopener noreferrer\">Lirę</a>.", "Lauretta": "<b>Loreta</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielski</a> odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Laura\" target=\"_blank\" rel=\"noopener noreferrer\">Laura</a>. Forma powstała przez redukcję <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> zdrobnienia tego imienia do <i>Lauretta</i>.", "Lucyla": "<b>Lucyla</b>, <b>Lucylla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa <i>lux</i>, czyli \"światło\", odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Lucyliusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lucyliusz</a>. Jego patronką jest św. Lucyla, męczennica.", "Lilioza": "<b>Lilioza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Patronką tego imienia jest św. Lilioza z <a href=\"https://pl.wikipedia.org/wiki/Kordowa\" target=\"_blank\" rel=\"noopener noreferrer\">Kordowy</a>, wspominana razem ze swoim małżonkiem, św. Feliksem.", "Lubosława": "<b>Lubosława</b> – żeńska odmiana <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Lubos%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Lubosław</a>.", "Ładysława": "<b>Władysława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Władysław</a>. Istnieje również bardzo rzadko występująca forma <i>Ładysława</i>, stanowiąca zapożyczenie z języków sąsiednich, zwł. czeskiego i słowackiego, a także forma <b><a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Włodzisława</a></b> – nienotowana w dawnych źródłach, lecz stanowiąca odpowiednik staropolskiego imienia <a href=\"https://pl.wikipedia.org/wiki/W%C5%82odzis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Włodzisław</a>, które pod wpływem języka czeskiego przybrało formę <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Władysław</a>.", "Liba": "<b>Liba</b> lub <i><b>Libia</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, którego patronką jest św. Liba, wspominana razem ze swoimi towarzyszkami, św. Leonidą i Eutropią. W literaturze hagiograficznej Libę (Libię) oznacza się przemiennie tym imieniem oraz imieniem <a href=\"https://pl.wikipedia.org/wiki/Oliwia\" target=\"_blank\" rel=\"noopener noreferrer\">Oliwia</a>.", "Łada": "<b>Łada</b> – jednoczłonowy <a href=\"https://pl.wikipedia.org/wiki/Antroponimia\" target=\"_blank\" rel=\"noopener noreferrer\">antroponim</a> męski pochodzenia słowiańskiego o charakterze przezwiskowym, od <i>*lada</i> – \"porządek, rządność\".", "Lorelei": "<b>Lorelei</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego <a href=\"https://pl.wikipedia.org/wiki/Syrena_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">syrenę</a>.", "Laurentyna": "<b>Laurentyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Laurentyn\" target=\"_blank\" rel=\"noopener noreferrer\">Laurentyn</a> i <a href=\"https://pl.wikipedia.org/wiki/Wawrzyniec\" target=\"_blank\" rel=\"noopener noreferrer\">Wawrzyniec</a>. Patronką tego imienia jest bł. siostra <a href=\"https://pl.wikipedia.org/wiki/Maria_Laurentyna_od_%C5%9Bw._Stanis%C5%82awa_Prin\" target=\"_blank\" rel=\"noopener noreferrer\">Laurentyna (Jane Reiné Prin)</a>.", "Libusza": "<b>Libusza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię żeńskie</a> czeskiego pochodzenia (Libuše).", "Liberata": "<b>Liberata</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Liberat\" target=\"_blank\" rel=\"noopener noreferrer\">Liberat</a> oznaczające osobę \"uwolnioną\", \"wyzwoloną\". Patronką tego imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Liberata_i_Faustyna\" target=\"_blank\" rel=\"noopener noreferrer\">św. Liberata z Como</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VI wieku</a> i św. Liberata z Luzytanii żyjąca w II wieku.", "Lagertha": "Jej imię zapisane przez Saxo w wersji <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a>, <b>Lathgertha</b>, pochodzi ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyckiego</a> Hlaðgerðr (Hlathgerth). W anglojęzycznych źródłach jest często tłumaczona jako <b>„Lagertha”</b>, a także jako <b>Ladgertha</b>, <b>Ladgerda</b> lub podobnie.", "Lamberta": "<b>Lamberta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Lambert\" target=\"_blank\" rel=\"noopener noreferrer\">Lambert</a>.", "Łucjana": "<b>Łucjana</b> – żeńskie imię pochodzenia łacińskiego. Oznacza <i>należącą do rodu Lucjuszów</i>. Męski odpowiednik tego imienia to <a href=\"https://pl.wikipedia.org/wiki/%C5%81ucjan\" target=\"_blank\" rel=\"noopener noreferrer\">Łucjan</a>. Dawniej wiele imion na <i>L</i> w staropolskim języku przepisywano na <i>Ł</i>. Inna forma tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Lucjana\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjana</a>.", "Leoncja": "<b>Leoncja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Leoncjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Leoncjusz</a>, które to jest zdrobnieniem od imion, w których skład wchodziła cząstka <i>leon-</i>, takich jak <i>Leontoménēs</i>.", "Lucilla": "Od 164, po zaślubinach w <a href=\"https://pl.wikipedia.org/wiki/Efez\" target=\"_blank\" rel=\"noopener noreferrer\">Efezie</a>, małżonka <a href=\"https://pl.wikipedia.org/wiki/Cesarze_rzymscy\" target=\"_blank\" rel=\"noopener noreferrer\">cesarza rzymskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Lucjusz_Werus\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusza Werusa</a>, z którym miała córkę nieznanego imienia. Po jego śmierci poślubiła w 169 wysokiego dowódcę, Tytusa Klaudiusza Pompejanusa, z którym miała syna – Tyberiusza Klaudiusza Pompejanusa Kwintianusa, zwanego Pompejanusem, późniejszego senatora. W 182 została przez brata (cesarza <a href=\"https://pl.wikipedia.org/wiki/Kommodus\" target=\"_blank\" rel=\"noopener noreferrer\">Kommodusa</a>) pod zarzutem udziału w spisku zesłana na wyspę <a href=\"https://pl.wikipedia.org/wiki/Capri\" target=\"_blank\" rel=\"noopener noreferrer\">Capri</a> (<i>Capreae</i>), a następnie tam z jego rozkazu zamordowana.", "Lawenda": "Różne gatunki lawendy, a zwłaszcza <a href=\"https://pl.wikipedia.org/wiki/Poliploidalno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">tetraploidalny</a> <a href=\"https://pl.wikipedia.org/wiki/Mieszaniec\" target=\"_blank\" rel=\"noopener noreferrer\">mieszaniec</a> <i>L. ×intermedia</i>, są rozpowszechnione w uprawie. Do bardziej mrozoodpornych należy <a href=\"https://pl.wikipedia.org/wiki/Lawenda_w%C4%85skolistna\" target=\"_blank\" rel=\"noopener noreferrer\">lawenda wąskolistna</a> <i>L. angustifolia</i>. Roślina ta dobrze zaaklimatyzowała się także w południowych rejonach Polski. Sadzona jest głównie w ogrodach, pożytkowana na plantacjach. Biorąc pod uwagę południowe pochodzenie, najlepsze pod uprawę tej rośliny są pola osłonięte od zimnych wiatrów i nasłonecznione. Najlepiej udaje się na glebach ciepłych, przepuszczalnych, piaszczystych o odczynie zasadowym.", "Leopoldina": "Teren obowiązywania Leopoldiny był ograniczony do niektórych posiadłości <a href=\"https://pl.wikipedia.org/wiki/Habsburgowie\" target=\"_blank\" rel=\"noopener noreferrer\">Habsburgów</a> we Włoszech, jednak przyczynił się do rozpowszechnienia reformatorskich idei oświecenia w zakresie <a href=\"https://pl.wikipedia.org/wiki/Prawo_karne\" target=\"_blank\" rel=\"noopener noreferrer\">prawa karnego</a>.", "Leokrycja": "<b>Leokrycja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające „ukoronowana”, „królowa”. Patronką tego imienia jest św. Leokrycja z <a href=\"https://pl.wikipedia.org/wiki/Kordoba\" target=\"_blank\" rel=\"noopener noreferrer\">Kordowy</a>.", "L.": "<b>L.</b> – <a href=\"https://pl.wikipedia.org/wiki/Skr%C3%B3t\" target=\"_blank\" rel=\"noopener noreferrer\">skrót</a> stosowany w <a href=\"https://pl.wikipedia.org/wiki/Botanika\" target=\"_blank\" rel=\"noopener noreferrer\">botanice</a>, umieszczany przy naukowej nazwie <a href=\"https://pl.wikipedia.org/wiki/Takson\" target=\"_blank\" rel=\"noopener noreferrer\">taksonu</a>, którego <a href=\"https://pl.wikipedia.org/wiki/Autor_nazwy_(botanika)\" target=\"_blank\" rel=\"noopener noreferrer\">autorem</a> jest <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">Karol Linneusz</a>. Skrót ten oznacza, że Linneusz jako pierwszy opublikował w publikacji naukowej diagnozę taksonomiczną danego taksonu.", "Lubosza": "<b>Lubomira</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Lubomir_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lubomir</a>/<a href=\"https://pl.wikipedia.org/wiki/Lubomir_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lubomirz</a>, nienotowany w źródłach staropolskich. Znaczenie imienia: „miłująca pokój”."};
